static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // conservative per-core
static constexpr uint32_t ALIGN_ELEMS = 64;
static constexpr uint32_t MAX_ROWS_PER_BLOCK = 16;       // avoid large per-iter latency

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    LogSoftmaxCustomTilingData tiling;
    const gert::Shape *xShape = context->GetInputShape(0)->GetOriginShape();
    uint32_t totalLength = static_cast<uint32_t>(xShape->GetShapeSize());

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    int32_t dim = *attrs->GetAttrPointer<int32_t>(0);

    // For 2D input, if dim==1, rowLength = shape[1], else shape[0]
    uint32_t rowLength = static_cast<uint32_t>(xShape->GetDim(1));
    uint32_t numRows = static_cast<uint32_t>(xShape->GetDim(0));

    // We assume each block processes a group of entire rows.
    // Each row needs UB space: x, y, and intermediates.
    // For simplicity we let each row consume 3 * rowLength * sizeof(float) bytes.
    uint32_t rowUbBytes = rowLength * 3 * sizeof(float);
    uint32_t maxRowsInUb = UB_BUDGET_BYTES / rowUbBytes;
    if (maxRowsInUb > MAX_ROWS_PER_BLOCK) maxRowsInUb = MAX_ROWS_PER_BLOCK;
    if (maxRowsInUb < 1) maxRowsInUb = 1;

    uint32_t rowsPerTile = std::min(maxRowsInUb, numRows);
    uint32_t tileLength = rowsPerTile * rowLength;

    // Block dimension: number of tiles
    uint32_t numTiles = CeilDiv(numRows, rowsPerTile);
    uint32_t blockDim = numTiles;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

